import functools

def preserve_metadata(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f"Running {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

@preserve_metadata
def greet(name):
    """Returns a greeting message"""
    return f"Hello, {name}!"

print(greet.__name__)  # Output: greet
print(greet.__doc__)   # Output: Returns a greeting message

import time
import functools

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__} took {end - start:.4f} seconds to run")
        return result
    return wrapper

@timer
def countdown(n):
    while n > 0:
        n -= 1

countdown(1000000)

def requires_admin(func):
    @functools.wraps(func)
    def wrapper(user, *args, **kwargs):
        if not user.get('is_admin', False):
            print("Access denied! Admins only.")
            return None
        return func(user, *args, **kwargs)
    return wrapper

@requires_admin
def delete_database(user):
    print("Database deleted!")

user = {'username': 'jane', 'is_admin': False}
admin = {'username': 'john', 'is_admin': True}

delete_database(user)   # Access denied! Admins only.
delete_database(admin)  # Database deleted!

